```python
@pytest.fixture(scope='module')  # 'function' or 'module'
def boto_session():
    session = boto3.session.Session()
    pill = placebo.attach(session, data_path=here('./resources/placebo'))
    if os.getenv('PLACEBO_MODE').lower() == 'record':
        pill.record()
    else:
        pill.playback()
    yield session
```

