In Python you can always wrap a decorator with your own decorator, something like:

```python
ratelimiter = ratelimit(key='ip', rate='100/h', ...)

def ratelimit_if_whitelisted(view):
    ratelimited_view = ratelimiter(view)
    
    @functools.wraps(view)
    def wrapper(request, *args, **kwargs):
        if is_whitelisted(request):
            return view(request, *args, **kwargs)
        return ratelimited_view(request, *args, **kwargs)

    return wrapper

@ratelimit_if_whitelisted
def my_view(request, user_id):
    return HttpResponse('hi')
```

