Hi @lorenzofox3,

Thanks for your comment, it gave me in insight in how to fix this neatly. I didn't manage to get your example working but it did inspire me to refactor my own.

This is what works for me now. It can probably be optimised but it's enough for my use case now. 

Thanks a lot for this project!

```js
app.directive('csSelectAll', function () {
  return {
    require: '^stTable',
    template: '<input type="checkbox" ng-model="isAllSelected"/>',
    scope: {
      rows: '=csSelectAll'
    },
    link: function (scope) {

      function getAllSelected() {
        return (getTotalRows() === getSelectedRows());
      }

      function getTotalRows() {
        return scope.rows.length;
      }

      function getSelectedRows() {
        var selectedRows = 0;
        scope.rows.forEach(function (row) {
          if (row.isSelected) {
            selectedRows++;
          }
        });
        return selectedRows;
      }

      function setAllRows(bool) {
        scope.rows.forEach(function (row) {
          if (!row.isSelected == bool) {
            row.isSelected = bool;
          }
        });
      }

      scope.$watch('rows', function () {
        scope.isAllSelected = getAllSelected();
      }, true);

      scope.$watch('isAllSelected', function () {
        if (scope.isAllSelected) {
          setAllRows(true);
        } else {
          if (getAllSelected()) {
            setAllRows(false);
          }
        }
      });

    }
  };
});
```

